// Define the contract:
public interface PocViewContract {
    void setResponseText(String text);
    void clearFormFields();
    PersonFormData getFormData();
    void showError(String message);
    void addSubmitListener(Runnable onSubmit);
}

// PocView implements it:
public class PocView implements PocViewContract {
    private JTextArea textArea = new JTextArea();
    // ... other private fields

    @Override
    public void setResponseText(String text) {
        SwingUtilities.invokeLater(() -> textArea.setText(text));
    }

    @Override
    public void clearFormFields() {
        SwingUtilities.invokeLater(() -> {
            firstName.setText("");
            name.setText("");
            // ...
        });
    }
}

// PocPresenter only knows the interface:
public class PocPresenter {
    public PocPresenter(PocViewContract view, PocModel model, EventEmitter emitter) {
        emitter.subscribe(data -> view.setResponseText(data));
        view.addSubmitListener(() -> model.action());
    }
}

