// Java - PocModel unit test:
@ExtendWith(MockitoExtension.class)
class PocModelTest {
    @Mock PostService postService;
    @Mock EventEmitter emitter;

    @Test
    void action_shouldThrowValidation_whenRequiredFieldsNull() {
        var model = new PocModel(emitter, postService);
        assertThrows(ValidationException.class, model::action);
        verifyNoInteractions(postService);
    }

    @Test
    void action_shouldEmitResponse_whenPostSucceeds() throws Exception {
        var model = new PocModel(emitter, postService);
        model.setProperty(ModelProperties.FIRST_NAME, "Hans");
        // ... set all required fields
        when(postService.post(any())).thenReturn("{\"status\":\"ok\"}");
        model.action();
        verify(emitter).emit("{\"status\":\"ok\"}");
    }
}

