public record PersonData(
    @NotBlank String firstName,
    @NotBlank String lastName,
    @NotNull LocalDate dateOfBirth,
    @NotNull GenderOption gender,
    String iban,
    String bic,
    String street,
    String zip,
    String ort,
    LocalDate validFrom
) {}

// PersonDataValidator:
public class PersonDataValidator {
    public List<String> validate(PersonData data) {
        List<String> errors = new ArrayList<>();
        if (data.firstName() == null || data.firstName().isBlank())
            errors.add("Vorname ist erforderlich");
        if (data.iban() != null && !isValidIban(data.iban()))
            errors.add("IBAN hat ungültiges Format");
        if (data.dateOfBirth() != null && data.dateOfBirth().isAfter(LocalDate.now()))
            errors.add("Geburtsdatum darf nicht in der Zukunft liegen");
        return errors;
    }
}

// PocModel.action() with validation:
public void action() throws ValidationException {
    var data = buildPersonData();
    var errors = validator.validate(data);
    if (!errors.isEmpty()) throw new ValidationException(errors);
    var payload = serializer.toMap(data);
    var response = httpService.post(payload);
    eventEmitter.emit(response);
}

// WebSocketService using Tyrus:
@ClientEndpoint
public class WebSocketService {
    private Session session;
    private final EventEmitter emitter;

    public WebSocketService(EventEmitter emitter) {
        this.emitter = emitter;
    }

    public void connect(String serverUri) throws Exception {
        WebSocketContainer container = ContainerProvider.getWebSocketContainer();
        container.connectToServer(this, URI.create(serverUri));
    }

    @OnMessage
    public void onMessage(String message) {
        emitter.emit(message);
    }

    @OnClose
    public void onClose(Session session, CloseReason reason) {
        log.info("WebSocket closed: {}", reason.getReasonPhrase());
    }
}

